import React from 'react';

const styleMap = {
  normal:    { fontFamily: "'Cormorant Garamond', serif", fontSize: 'clamp(9px,1.25vw,13px)', fontStyle: 'normal', fontWeight: 300, letterSpacing: '0.01em' },
  elegant:   { fontFamily: "'IM Fell English', serif", fontSize: 'clamp(9px,1.2vw,12.5px)', fontStyle: 'italic', fontWeight: 400, letterSpacing: '0.02em' },
  bold:      { fontFamily: "'Cinzel', serif", fontSize: 'clamp(8px,1.1vw,11.5px)', fontStyle: 'normal', fontWeight: 600, letterSpacing: '0.04em' },
  wide:      { fontFamily: "'Cormorant Garamond', serif", fontSize: 'clamp(9px,1.25vw,13px)', fontStyle: 'normal', fontWeight: 300, letterSpacing: '0.12em', lineHeight: 2 },
  condensed: { fontFamily: "'Cormorant Garamond', serif", fontSize: 'clamp(8.5px,1.2vw,12.5px)', fontStyle: 'normal', fontWeight: 400, lineHeight: 1.55, letterSpacing: '-0.01em' },
};

export default function PageContent({ page, side }) {
  const textStyle = styleMap[page.textStyle] || styleMap.normal;

  return (
    <div className={`pg pg-${side}`}>
      <div className="pg-deco" />
      <div className="pg-body">
        <span className="pg-chapter">{page.chapter}</span>
        <h2 className="pg-title">{page.title}</h2>
        <div className="pg-rule" />

        {page.image && (
          <div className="pg-image-wrap">
            <img src={page.image} alt={page.imageCaption || page.title} className="pg-image" />
            {page.imageCaption && <p className="pg-caption">{page.imageCaption}</p>}
          </div>
        )}

        <p className="pg-text" style={textStyle}>{page.content}</p>

        {page.quote && (
          <blockquote className="pg-quote">
            <span className="pg-qmark">"</span>
            <em>{page.quote}</em>
          </blockquote>
        )}

        <span className={`pg-num pg-num-${side}`}>{page.pageNum}</span>
      </div>
      <div className={`pg-fold pg-fold-${side}`} />

      <style>{`
        .pg {
          position:relative; background:var(--parchment); overflow:hidden;
          height:100%; display:flex; flex-direction:column;
        }
        .pg-left  { border-right:1px solid var(--border-page); }
        .pg-right { border-left:1px solid var(--border-page); }

        .pg-deco {
          position:absolute; inset:10px; border:1px solid rgba(160,130,60,.15);
          pointer-events:none;
        }

        .pg-body {
          position:relative; z-index:2;
          padding: clamp(18px,3.5%,48px) clamp(18px,4.5%,52px);
          height:100%; display:flex; flex-direction:column; overflow:hidden;
        }

        .pg-chapter {
          display:block;
          font-family:'Cinzel',serif; font-size:clamp(6px,.9vw,9px);
          letter-spacing:.35em; color:rgba(140,100,40,.6);
          text-transform:uppercase; margin-bottom:7px;
        }
        .pg-title {
          font-family:'Cinzel',serif;
          font-size:clamp(12px,2vw,20px);
          color:var(--ink); font-weight:600; line-height:1.2; margin-bottom:10px;
        }
        .pg-rule {
          width:38px; height:1px; margin-bottom:12px;
          background:linear-gradient(90deg,transparent,rgba(160,120,40,.5),transparent);
        }

        .pg-image-wrap {
          margin-bottom:12px; text-align:center;
        }
        .pg-image {
          max-height:clamp(80px,14vw,160px); max-width:100%;
          border-radius:3px; object-fit:cover;
          border:1px solid rgba(160,130,60,.25);
          box-shadow:0 4px 16px rgba(0,0,0,.15);
        }
        .pg-caption {
          font-family:'IM Fell English',serif; font-style:italic;
          font-size:clamp(7px,1vw,10px); color:var(--ink-faint);
          margin-top:5px; line-height:1.4;
        }

        .pg-text {
          flex:1; overflow:hidden; color:var(--ink-light);
          line-height:1.75; white-space:pre-line;
          transition:all .3s;
        }

        .pg-quote {
          margin-top:12px; padding:8px 12px;
          border-left:2px solid rgba(160,120,40,.35);
          background:rgba(160,120,40,.04);
          font-size:clamp(7.5px,1vw,10.5px);
          color:rgba(80,60,20,.65); line-height:1.5;
        }
        .pg-qmark {
          font-size:2em; line-height:0; vertical-align:-.3em;
          color:rgba(160,120,40,.35); margin-right:3px;
        }

        .pg-num {
          position:absolute; bottom:18px;
          font-family:'Cinzel',serif; font-size:9px;
          color:rgba(140,110,50,.45); letter-spacing:.2em;
        }
        .pg-num-left  { left:clamp(18px,4.5%,52px); }
        .pg-num-right { right:clamp(18px,4.5%,52px); }

        .pg-fold { position:absolute; bottom:0; width:0; height:0; border-style:solid; }
        .pg-fold-left  { left:0;  border-width:0 22px 22px 0; border-color:transparent rgba(200,180,130,.25) transparent transparent; }
        .pg-fold-right { right:0; border-width:0 0 22px 22px; border-color:transparent transparent rgba(200,180,130,.25) transparent; }
      `}</style>
    </div>
  );
}
